using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so we must preserve it.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF 9 uses only the raw key for "id" (e.g. "1").
            // Existing documents use "Blog|1" format, so we must preserve it.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .HasJsonPropertyName("id")
                  .ToJsonProperty("id");

            // Breaking change 3: Cosmos DB does not support indexing in EF 9
            // the same way. HasIndex() on Cosmos now throws by default.
            // Removed: entity.HasIndex(b => b.Name);
            // Cosmos manages indexes at the container level via indexing policy,
            // not through EF model configuration.
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change 2 (cont.): Restore the "EntityType|Key" id format
        // used by EF 8 for existing documents.
        configurationBuilder.Conventions.Add(_ =>
            new IdFormatConvention());
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

