using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;
using Microsoft.EntityFrameworkCore.Metadata.Conventions;

// Restores EF Core 8's "Discriminator|Key" id format for backward compatibility
// with existing Cosmos DB documents.
class IdFormatConvention : IModelFinalizingConvention
{
    public void ProcessModelFinalizing(
        IConventionModelBuilder modelBuilder,
        IConventionContext<IConventionModelBuilder> context)
    {
        foreach (var entityType in modelBuilder.Metadata.GetEntityTypes())
        {
            var idProperty = entityType.FindProperty("__id");
            if (idProperty is not null)
            {
                // Override the default id factory to produce "EntityType|Key"
                idProperty.SetValueGeneratorFactory(
                    (property, type) => new LegacyIdValueGenerator(entityType.ShortName()));
            }
        }
    }
}

using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

// Generates ids in the EF Core 8 format: "Discriminator|KeyValue"
class LegacyIdValueGenerator : ValueGenerator<string>
{
    private readonly string _discriminator;

    public LegacyIdValueGenerator(string discriminator) => _discriminator = discriminator;

    public override bool GeneratesTemporaryValues => false;

    protected override string GenerateNext(EntityEntry entry)
    {
        var keyProperty = entry.Metadata.FindPrimaryKey()!.Properties[0];
        var keyValue = entry.Property(keyProperty.Name).CurrentValue;
        return $"{_discriminator}|{keyValue}";
    }
}

