class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Existing documents use
            // "Discriminator", so we must preserve the old name.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Blog>("Blog");
            entity.Property<string>("Discriminator")
                  .ToJsonProperty("Discriminator");

            // Breaking change 2: EF 9 uses only the raw key for the JSON "id"
            // property (e.g. "1"). Existing documents use "Blog|1" format.
            // We handle this via IdFormatConvention + LegacyIdValueGenerator.

            // Breaking change 3: HasIndex() on Cosmos now throws at runtime.
            // Cosmos manages indexes at the container level via indexing policy.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Register the convention that restores EF 8's "EntityType|Key" id format.
        configurationBuilder.Conventions.Add(_ => new IdFormatConvention());
    }
}
